from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time

app = Flask(__name__)

# Request counters
REQUEST_COUNT = Counter('flask_requests_total', 'Total requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('flask_request_duration_seconds', 'Request duration in seconds', ['method', 'endpoint'])
ACTIVE_REQUESTS = Gauge('flask_active_requests', 'Number of active requests')

# Business metrics
BUSINESS_METRICS = Counter('business_operations_total', 'Total business operations', ['operation', 'status'])

@app.before_request
def before_request():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def after_request(response):
    ACTIVE_REQUESTS.dec()
    
    # Record request metrics
    duration = time.time() - request.start_time
    REQUEST_LATENCY.labels(method=request.method, endpoint=request.endpoint or 'unknown').observe(duration)
    REQUEST_COUNT.labels(method=request.method, endpoint=request.endpoint or 'unknown', status=response.status_code).inc()
    
    return response

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})

@app.route('/business/<operation>')
def business_operation(operation):
    # Simulate business operation
    time.sleep(0.1)
    
    try:
        # Simulate some business logic
        if operation == 'create':
            BUSINESS_METRICS.labels(operation='create', status='success').inc()
            return jsonify({'result': 'created'})
        elif operation == 'delete':
            BUSINESS_METRICS.labels(operation='delete', status='success').inc()
            return jsonify({'result': 'deleted'})
        else:
            BUSINESS_METRICS.labels(operation=operation, status='error').inc()
            return jsonify({'error': 'unknown operation'}), 400
    except Exception as e:
        BUSINESS_METRICS.labels(operation=operation, status='error').inc()
        return jsonify({'error': str(e)}), 500

@app.route('/metrics')
def metrics():
    return generate_latest()

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)